/**
 * Tests for the EngramSearchSource — validates mapping, formatting,
 * and error handling without needing a running mm CLI.
 *
 * Run: npx tsx test/engram-search.test.ts
 */
import { resolveRecallConfig } from "../src/config.js";
import type { RecallSnippet } from "../src/types.js";
import {
  EngramSearchSource,
  type EngramApi,
  type EngramSearchResult,
} from "../src/sources/engram-search.js";

let passed = 0;
let failed = 0;

function assert(condition: boolean, name: string) {
  if (condition) {
    passed++;
    console.log(`  ✅ ${name}`);
  } else {
    failed++;
    console.log(`  ❌ ${name}`);
  }
}

// === Helpers ===

function createMockApi(results: EngramSearchResult[]): EngramApi {
  return {
    search: async (_query: string, _excludeModels?: string[]) => results,
  };
}

function createFailingApi(): EngramApi {
  return {
    search: async () => {
      throw new Error("CLI not found");
    },
  };
}

function createExcludeTrackingApi(
  results: EngramSearchResult[],
): EngramApi & { lastExcludes: string[] | undefined } {
  const tracker = {
    lastExcludes: undefined as string[] | undefined,
    search: async (_query: string, excludeModels?: string[]) => {
      tracker.lastExcludes = excludeModels;
      return results;
    },
  };
  return tracker;
}

const sampleResults: EngramSearchResult[] = [
  {
    model: "chitin",
    modelType: "code",
    node: {
      label: "RetrievalEngine",
      type: "module",
      metadata: { file: "src/engine/retrieve.ts" },
    },
    edges: [
      { direction: "out", relationship: "uses", target: "EmbeddingStore" },
      { direction: "out", relationship: "uses", target: "context-detect" },
      { direction: "out", relationship: "uses", target: "decay" },
      { direction: "in", relationship: "uses", source: "index.ts" },
    ],
  },
  {
    model: "hashbranch-e2e",
    modelType: "code",
    node: {
      label: "fleet-rest",
      type: "service",
      metadata: {},
    },
    edges: [
      { direction: "out", relationship: "calls", target: "payment-rest" },
      { direction: "in", relationship: "calls", source: "medusa-server" },
    ],
  },
];

async function runTests() {
  // === Mapping Tests ===
  console.log("\n📊 Maps mm search JSON output to RecallSnippet[]");

  const source = new EngramSearchSource(createMockApi(sampleResults), 5);
  // Use query terms that match the sample data: "RetrievalEngine" and "fleet-rest"
  const snippets = await source.search("RetrievalEngine fleet-rest", 0.1);

  assert(snippets.length === 2, "returns correct number of snippets");
  assert(snippets[0].source === "engram", "source is engram");
  assert(snippets[0].path.startsWith("engram/"), "path is engram/<model>");
  assert(snippets[0].score > 0, "score is positive (relevance-based)");
  assert(snippets[0].score <= 1.0, "score is at most 1.0");

  // === Snippet Text Formatting ===
  console.log("\n📝 Formats snippet text with edges");

  // Find snippets by reference (order depends on relevance score now)
  const chitinSnippet = snippets.find(s => s.reference.includes("RetrievalEngine"));
  const fleetSnippet = snippets.find(s => s.reference.includes("fleet-rest"));
  assert(chitinSnippet !== undefined, "RetrievalEngine result found");
  assert(fleetSnippet !== undefined, "fleet-rest result found");

  const text = chitinSnippet!.text;
  assert(text.includes("Model: chitin (code)"), "includes model name and type");
  assert(text.includes("RetrievalEngine (module)"), "includes node label and type");
  assert(text.includes("→ uses:"), "includes outgoing edges");
  assert(text.includes("EmbeddingStore"), "includes outgoing target");
  assert(text.includes("context-detect"), "includes second outgoing target");
  assert(text.includes("decay"), "includes third outgoing target");
  assert(text.includes("← uses:"), "includes incoming edges");
  assert(text.includes("index.ts"), "includes incoming source");

  const text2 = fleetSnippet!.text;
  assert(text2.includes("Model: hashbranch-e2e (code)"), "fleet result has correct model");
  assert(text2.includes("fleet-rest (service)"), "fleet result has correct node");
  assert(text2.includes("→ calls: payment-rest"), "fleet result has outgoing");
  assert(text2.includes("← calls: medusa-server"), "fleet result has incoming");

  // === Empty Results ===
  console.log("\n🚫 Empty results handled gracefully");

  const emptySource = new EngramSearchSource(createMockApi([]), 3);
  const emptySnippets = await emptySource.search("nothing", 0.0);
  assert(emptySnippets.length === 0, "returns empty array for no results");

  // === CLI Errors ===
  console.log("\n💥 CLI errors return empty array (never throw)");

  const failSource = new EngramSearchSource(createFailingApi(), 3);
  const failSnippets = await failSource.search("RetrievalEngine", 0.1);
  assert(failSnippets.length === 0, "returns empty array on CLI error");

  // === Exclude Models ===
  console.log("\n🔒 Exclude models passed through correctly");

  const tracker = createExcludeTrackingApi(sampleResults);
  const excludeSource = new EngramSearchSource(tracker, 3, ["zink-family", "test-model"]);
  await excludeSource.search("RetrievalEngine fleet", 0.1);
  assert(
    tracker.lastExcludes !== undefined &&
      tracker.lastExcludes.includes("zink-family") &&
      tracker.lastExcludes.includes("test-model"),
    "exclude models passed to API",
  );

  // === Max Results Limit ===
  console.log("\n📏 Max results limit");

  const manyResults: EngramSearchResult[] = Array.from({ length: 10 }, (_, i) => ({
    model: `model-${i}`,
    modelType: "code",
    node: { label: `TestNode${i}`, type: "service", metadata: {} },
    edges: [],
  }));
  const limitedSource = new EngramSearchSource(createMockApi(manyResults), 3);
  // Use "TestNode" which matches all labels
  const limitedSnippets = await limitedSource.search("TestNode", 0.1);
  assert(limitedSnippets.length === 3, "respects maxResults limit");

  // === Node Without Type ===
  console.log("\n🏷️ Node without type");

  const noTypeResult: EngramSearchResult[] = [{
    model: "concepts",
    modelType: "concept",
    node: { label: "SomeIdea", type: null, metadata: {} },
    edges: [],
  }];
  const noTypeSource = new EngramSearchSource(createMockApi(noTypeResult), 3);
  const noTypeSnippets = await noTypeSource.search("SomeIdea", 0.1);
  assert(noTypeSnippets.length === 1, "handles null type");
  assert(noTypeSnippets[0].text.includes("SomeIdea"), "text includes label");
  assert(!noTypeSnippets[0].text.includes("(null)"), "text does not include (null)");

  // === Node Without Edges ===
  console.log("\n🔗 Node without edges");

  const noEdgesResult: EngramSearchResult[] = [{
    model: "orphans",
    modelType: "code",
    node: { label: "Isolated", type: "util", metadata: {} },
    edges: [],
  }];
  const noEdgesSource = new EngramSearchSource(createMockApi(noEdgesResult), 3);
  const noEdgesSnippets = await noEdgesSource.search("Isolated orphans", 0.1);
  assert(noEdgesSnippets.length === 1, "handles node with no edges");
  assert(noEdgesSnippets[0].text === "Model: orphans (code) | Isolated (util)", "text is just model and node info");

  // === Config Tests ===
  console.log("\n📋 Config resolution for engram");

  const defaultConfig = resolveRecallConfig(undefined);
  assert(defaultConfig.sources.engram.enabled === false, "default: disabled");
  assert(defaultConfig.sources.engram.command.includes("engram"), "default: command contains engram");
  assert(defaultConfig.sources.engram.maxResults === 5, "default: maxResults 5");
  assert(defaultConfig.sources.engram.excludeModels.length === 0, "default: no exclude models");

  const customConfig = resolveRecallConfig({
    sources: {
      engram: {
        enabled: true,
        maxResults: 5,
        excludeModels: ["private-model"],
      },
    },
  });
  assert(customConfig.sources.engram.enabled === true, "custom: enabled");
  assert(customConfig.sources.engram.maxResults === 5, "custom: maxResults 5");
  assert(customConfig.sources.engram.excludeModels.includes("private-model"), "custom: exclude models set");

  // === Relevance Scoring ===
  console.log("\n📊 Relevance scoring");

  // Query "Tom Merkle" should score Tom-Merkle higher than unrelated nodes
  const scoringResults: EngramSearchResult[] = [
    {
      model: "hashbranch",
      modelType: "org",
      node: { label: "Tom-Merkle", type: "person", metadata: { role: "CEO" } },
      edges: [{ direction: "out", relationship: "leads", target: "Hashbranch" }],
    },
    {
      model: "chitin",
      modelType: "code",
      node: { label: "EmbeddingFactory", type: "function", metadata: {} },
      edges: [{ direction: "out", relationship: "produces", target: "EmbeddingProvider" }],
    },
    {
      model: "hashbranch",
      modelType: "org",
      node: { label: "Hashbranch", type: "org", metadata: {} },
      edges: [{ direction: "in", relationship: "leads", source: "Tom-Merkle" }],
    },
  ];

  const scoringSource = new EngramSearchSource(createMockApi(scoringResults), 5);

  // "Tom Merkle" should return Tom-Merkle and Hashbranch (via edge), NOT EmbeddingFactory
  const tomResults = await scoringSource.search("Tom Merkle", 0.1);
  const tomLabels = tomResults.map(s => s.reference);
  assert(
    tomLabels.some(r => r.includes("Tom-Merkle")),
    "Tom-Merkle appears in results for 'Tom Merkle' query",
  );
  assert(
    tomResults.find(s => s.reference.includes("Tom-Merkle"))!.score >
    (tomResults.find(s => s.reference.includes("EmbeddingFactory"))?.score ?? 0),
    "Tom-Merkle scores higher than EmbeddingFactory for 'Tom Merkle' query",
  );

  // With a higher minScore, EmbeddingFactory should be filtered out
  const strictTomResults = await scoringSource.search("Tom Merkle", 0.3);
  const strictLabels = strictTomResults.map(s => s.reference);
  assert(
    !strictLabels.some(r => r.includes("EmbeddingFactory")),
    "EmbeddingFactory filtered out at minScore=0.3 for 'Tom Merkle' query",
  );
  assert(
    strictLabels.some(r => r.includes("Tom-Merkle")),
    "Tom-Merkle survives minScore=0.3 for 'Tom Merkle' query",
  );

  // Query that matches nothing should return empty
  const noMatchResults = await scoringSource.search("ZephyrQuantum", 0.1);
  assert(noMatchResults.length === 0, "no results when query matches nothing");

  // Results are sorted by score descending
  const sortedResults = await scoringSource.search("Tom Merkle Hashbranch", 0.1);
  for (let i = 1; i < sortedResults.length; i++) {
    assert(
      sortedResults[i - 1].score >= sortedResults[i].score,
      `results sorted by score: [${i - 1}]=${sortedResults[i - 1].score.toFixed(2)} >= [${i}]=${sortedResults[i].score.toFixed(2)}`,
    );
  }

  // === Summary ===
  console.log(`\n${"=".repeat(40)}`);
  console.log(`Results: ${passed} passed, ${failed} failed`);
  if (failed > 0) process.exit(1);
}

runTests().catch((err) => {
  console.error("Test error:", err);
  process.exit(1);
});
